#include<string>
#include<cstring>
#include<iostream>
#include<algorithm>
using namespace std;

int dp[2005][2005];

int main(){
	string a, b;
	int n, m;
	cin >> a >> b;
	n = a.size();
	m = b.size();
	a = '#' + a;
	b = '#' + b;
	memset(dp, 0x3f, sizeof dp);
	dp[0][0] = 0;
	for(int i = 1; i <= n; i++)
		for(int j = 1; j <= m; j++)
		{
			dp[i][j] = min(dp[i - 1][j], dp[i][j - 1]) + 1;
			if(a[i] != b[j]) dp[i][j] = min(dp[i][j], dp[i - 1][j - 1] + 1);
			else dp[i][j] = min(dp[i][j], dp[i - 1][j - 1]);
		}
	cout << dp[n][m];
	return 0;
}
